UPDATE `notice_business_channel_template`
SET `title_template` = '账号注册成功通知',
    `content_template` = '<div style="margin:0;padding:0;background:#eef2f7;font-family:Arial,''Microsoft YaHei'',sans-serif;color:#182230;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background:#eef2f7;padding:32px 0;"><tr><td align="center"><table role="presentation" width="720" cellspacing="0" cellpadding="0" style="width:720px;max-width:100%;background:#ffffff;border:1px solid #d8e0ea;border-radius:14px;overflow:hidden;box-shadow:0 18px 45px rgba(15,23,42,.12);"><tr><td style="padding:0;background:#0f172a;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td style="padding:30px 34px;color:#ffffff;"><div style="font-size:13px;letter-spacing:.08em;text-transform:uppercase;color:#93c5fd;">Mango Notice Center</div><div style="font-size:30px;line-height:1.25;font-weight:700;margin-top:10px;">账号注册成功</div><div style="font-size:15px;line-height:1.7;color:#dbeafe;margin-top:12px;">欢迎 {{username}}，你的账号已完成初始化，可以开始使用管理后台。</div></td><td align="right" style="padding:30px 34px;width:170px;"><span style="display:inline-block;padding:8px 14px;border-radius:999px;background:#dcfce7;color:#166534;font-size:13px;font-weight:700;">已完成</span></td></tr></table></td></tr><tr><td style="padding:26px 34px 8px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="border-collapse:separate;border-spacing:0 14px;"><tr><td style="padding:18px 20px;background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;"><div style="font-size:13px;color:#64748b;margin-bottom:6px;">用户名称</div><div style="font-size:20px;font-weight:700;color:#111827;">{{username}}</div></td><td style="width:16px;"></td><td style="padding:18px 20px;background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;"><div style="font-size:13px;color:#64748b;margin-bottom:6px;">注册时间</div><div style="font-size:20px;font-weight:700;color:#111827;">{{registerTime}}</div></td></tr></table></td></tr><tr><td style="padding:10px 34px 4px;"><div style="font-size:16px;font-weight:700;margin-bottom:12px;color:#111827;">接下来你可以</div><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="border:1px solid #dbeafe;border-radius:10px;overflow:hidden;"><tr><td style="width:46px;padding:14px 0;text-align:center;background:#eff6ff;color:#2563eb;font-weight:700;">1</td><td style="padding:14px 18px;border-bottom:1px solid #e0ecff;"><div style="font-weight:700;color:#1e3a8a;">完善接收账号</div><div style="font-size:13px;color:#64748b;margin-top:4px;">绑定邮箱、手机号或其它通知账号，保证重要通知可达。</div></td></tr><tr><td style="width:46px;padding:14px 0;text-align:center;background:#f0fdf4;color:#16a34a;font-weight:700;">2</td><td style="padding:14px 18px;border-bottom:1px solid #dcfce7;"><div style="font-weight:700;color:#166534;">检查接收规则</div><div style="font-size:13px;color:#64748b;margin-top:4px;">按业务域和消息类型确认系统消息、短信、邮件等渠道是否接收。</div></td></tr><tr><td style="width:46px;padding:14px 0;text-align:center;background:#fff7ed;color:#ea580c;font-weight:700;">3</td><td style="padding:14px 18px;"><div style="font-weight:700;color:#9a3412;">查看消息记录</div><div style="font-size:13px;color:#64748b;margin-top:4px;">在消息中心查看历史通知、未读消息和发送状态。</div></td></tr></table></td></tr><tr><td style="padding:22px 34px 30px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;"><tr><td style="padding:18px 20px;line-height:1.8;color:#475569;">如果本次注册不是你本人操作，请不要点击任何链接，并联系系统管理员确认账号安全。</td><td align="right" style="padding:18px 20px;width:180px;"><a href="http://127.0.0.1:7777/" style="display:inline-block;background:#2563eb;color:#ffffff;text-decoration:none;padding:12px 18px;border-radius:7px;font-weight:700;">进入管理后台</a></td></tr></table></td></tr><tr><td style="padding:18px 34px;background:#f8fafc;color:#94a3b8;font-size:12px;border-top:1px solid #e5e7eb;">此邮件由 Mango 通知中心自动发送，请勿直接回复。若链接无法访问，请复制 http://127.0.0.1:7777/ 到浏览器打开。</td></tr></table></td></tr></table></div>',
    `updated_at` = NOW()
WHERE `biz_type` = 'auth.register_success'
  AND `channel_type` = 'EMAIL';

UPDATE `notice_business_channel_template`
SET `title_template` = '账号安全提醒',
    `content_template` = '<div style="margin:0;padding:0;background:#fff7ed;font-family:Arial,''Microsoft YaHei'',sans-serif;color:#1f2937;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background:#fff7ed;padding:32px 0;"><tr><td align="center"><table role="presentation" width="720" cellspacing="0" cellpadding="0" style="width:720px;max-width:100%;background:#ffffff;border:1px solid #fed7aa;border-radius:14px;overflow:hidden;box-shadow:0 18px 45px rgba(154,52,18,.14);"><tr><td style="padding:30px 34px;background:#7c2d12;color:#ffffff;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0"><tr><td><div style="font-size:13px;letter-spacing:.08em;color:#fed7aa;">SECURITY ALERT</div><div style="font-size:30px;font-weight:700;line-height:1.25;margin-top:10px;">账号安全提醒</div><div style="font-size:15px;line-height:1.7;color:#ffedd5;margin-top:12px;">系统检测到一条需要关注的账号安全事件，请及时确认。</div></td><td align="right" style="width:170px;"><span style="display:inline-block;padding:8px 14px;border-radius:999px;background:#fef3c7;color:#92400e;font-size:13px;font-weight:700;">需要关注</span></td></tr></table></td></tr><tr><td style="padding:28px 34px 10px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="border:1px solid #fdba74;border-radius:12px;background:#fffbeb;overflow:hidden;"><tr><td style="padding:18px 22px;border-bottom:1px solid #fed7aa;"><div style="font-size:13px;color:#92400e;margin-bottom:6px;">事件时间</div><div style="font-size:20px;font-weight:700;color:#7c2d12;">{{eventTime}}</div></td></tr><tr><td style="padding:18px 22px;"><div style="font-size:13px;color:#92400e;margin-bottom:6px;">风险原因</div><div style="font-size:17px;line-height:1.75;font-weight:600;color:#431407;">{{reason}}</div></td></tr></table></td></tr><tr><td style="padding:12px 34px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="border-collapse:separate;border-spacing:0 12px;"><tr><td style="width:8px;background:#f97316;border-radius:8px 0 0 8px;"></td><td style="padding:15px 18px;background:#fff7ed;border-top:1px solid #fed7aa;border-right:1px solid #fed7aa;border-bottom:1px solid #fed7aa;border-radius:0 8px 8px 0;color:#7c2d12;line-height:1.7;">如果该操作不是你本人触发，请立即修改密码，并检查账号绑定邮箱、手机号和最近登录记录。</td></tr><tr><td style="width:8px;background:#2563eb;border-radius:8px 0 0 8px;"></td><td style="padding:15px 18px;background:#eff6ff;border-top:1px solid #bfdbfe;border-right:1px solid #bfdbfe;border-bottom:1px solid #bfdbfe;border-radius:0 8px 8px 0;color:#1e3a8a;line-height:1.7;">建议启用多渠道接收规则，保证安全通知可以通过系统消息、邮件或短信及时触达。</td></tr></table></td></tr><tr><td style="padding:12px 34px 30px;"><table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:10px;"><tr><td style="padding:18px 20px;color:#475569;line-height:1.8;">你可以进入管理后台查看安全详情、消息记录和接收配置。</td><td align="right" style="padding:18px 20px;width:180px;"><a href="http://127.0.0.1:7777/" style="display:inline-block;background:#ea580c;color:#ffffff;text-decoration:none;padding:12px 18px;border-radius:7px;font-weight:700;">查看安全详情</a></td></tr></table></td></tr><tr><td style="padding:18px 34px;background:#fff7ed;color:#9a3412;font-size:12px;border-top:1px solid #fed7aa;">Mango 通知中心安全提醒邮件。若你确认账号存在风险，请联系管理员处理。</td></tr></table></td></tr></table></div>',
    `updated_at` = NOW()
WHERE `biz_type` = 'system.security_alert'
  AND `channel_type` = 'EMAIL';
